\documentclass{article}
\usepackage{amsmath,amsthm,amsfonts}
\begin{document}
\title{Derivation of the Euler--Lagrange Equation with Examples}
\author{A. Researcher}
\maketitle

\begin{abstract}
This note presents a worked derivation of the Euler--Lagrange equation for functionals defined on curves in $\mathbb{R}^n$. Several illustrative derivations are included, together with a short example demonstrating the application to a simple variational problem. The presentation is self-contained and uses standard variational notation.
\end{abstract}

\section{Introduction}
Let $\Omega \subset \mathbb{R}$ be an interval and consider a functional of the form
\begin{equation}\label{eq:functional}
J[y] = \int_{a}^{b} L\big(x,y(x),y'(x)\big)\,dx,
\end{equation}
where $y:\Omega\to\mathbb{R}^m$ and $L:\Omega\times\mathbb{R}^m\times\mathbb{R}^m\to\mathbb{R}$ is sufficiently smooth. We seek necessary conditions satisfied by a function $y$ that makes $J$ stationary under compactly supported perturbations.

\section{Preliminaries}
A variation is a family $y_\varepsilon(x)=y(x)+\varepsilon \eta(x)$, where $\eta(a)=\eta(b)=0$ and $\varepsilon\in\mathbb{R}$. The first variation is defined by
\begin{equation*}
\delta J[y;\eta] = \left.\frac{d}{d\varepsilon} J[y_\varepsilon]\right|_{\varepsilon=0}.
\end{equation*}
We compute this derivative under the integral sign, exchanging differentiation and integration since $L$ is smooth.

\section{Derivation}
Differentiating \eqref{eq:functional} for the varied curve gives
\begin{align}\label{eq:firstvar}
\delta J[y;\eta] &= \int_a^b \left( \partial_{y} L\cdot \eta + \partial_{y'} L\cdot \eta' \right) dx \\
&= \int_a^b \partial_{y} L\cdot \eta\,dx + \left[\partial_{y'} L\cdot \eta\right]_a^b - \int_a^b \frac{d}{dx}\big(\partial_{y'} L\big)\cdot \eta\,dx.
\end{align}
Using the boundary conditions $\eta(a)=\eta(b)=0$, the boundary term vanishes. Grouping terms, we obtain
\begin{equation}\label{eq:ELintegral}
\delta J[y;\eta] = \int_a^b \left( \partial_{y} L - \frac{d}{dx}\partial_{y'} L \right) \cdot \eta\,dx.
\end{equation}
Since $\eta$ is arbitrary, the fundamental lemma of the calculus of variations implies the Euler--Lagrange equation:
\begin{equation}\label{eq:EL}
\partial_{y} L\big(x,y,y'\big) - \frac{d}{dx}\partial_{y'} L\big(x,y,y'\big) = 0, \qquad x\in(a,b).
\end{equation}

\begin{theorem}[Euler--Lagrange]
Let $L$ be $C^2$ in its arguments. If $y\in C^2([a,b];\mathbb{R}^m)$ is a stationary point of $J$ under compactly supported variations, then $y$ satisfies \eqref{eq:EL}.
\end{theorem}

\begin{proof}
The computation in \eqref{eq:firstvar}--\eqref{eq:ELintegral} shows that for every $\eta$ with compact support the first variation vanishes. The fundamental lemma yields the pointwise equality of the integrand with zero, proving \eqref{eq:EL}.
\end{proof}

\section{A Worked Example}
Consider the classical problem of finding the shortest curve between two points in the plane. The length functional is
\begin{equation}\label{eq:length}
J[y] = \int_a^b \sqrt{1 + (y')^2}\,dx,
\end{equation}
with $y(a)=y_a$, $y(b)=y_b$. Here $L(x,y,y')=\sqrt{1+(y')^2}$, so $\partial_y L=0$ and $\partial_{y'} L= y' / \sqrt{1+(y')^2}$. The Euler--Lagrange equation \eqref{eq:EL} reduces to
\begin{equation}\label{eq:cline}
\frac{d}{dx}\left(\frac{y'}{\sqrt{1+(y')^2}}\right)=0.
\end{equation}
Integrating once yields
\begin{equation}\label{eq:cline2}
\frac{y'}{\sqrt{1+(y')^2}} = C,
\end{equation}
where $C$ is a constant. Solving for $y'$ gives $y'=C/(1-C^2)^{1/2}$, so $y$ is affine and therefore the shortest path is a straight line.

\section{Remarks}
The same derivation generalizes to higher-dimensional fields and to functionals with higher derivatives. In multiple dimensions one often uses the notation $x\in\mathbb{R}^n$ and considers integral functionals over domains; the variational derivative then leads to Euler--Lagrange systems. Conservation laws can be obtained via Noether's theorem when $L$ has symmetries.

\end{document}

%% Derivation sheet: variational approach to wave equations
\section*{Introduction}
This note presents a concise derivation of classical wave equations from a Lagrangian density, followed by a worked example for a one-dimensional vibrating string and a brief discussion of conserved quantities. The exposition uses the Euler--Lagrange formalism for fields and illustrates how dispersion relations arise for linear media. Propositions and proofs are stated in standard theorem environments.

\section{Lagrangian formulation for a scalar field}
Consider a real scalar field $\phi(x,t)$ in one spatial dimension with Lagrangian density
\begin{equation}\label{eq:lagrangian}
\mathcal{L}=\frac{1}{2}\rho\, (\partial_t\phi)^2 - \frac{1}{2}T\,(\partial_x\phi)^2 - V(\phi),
\end{equation}
where $\rho$ is the linear mass density, $T$ is the tension, and $V(\phi)$ is a potential term (for small oscillations we take $V(\phi)=\frac{1}{2}m^2\phi^2$). The action is
\begin{equation}
S[\phi]=\int dt\,dx\;\mathcal{L}(\phi,\partial_t\phi,\partial_x\phi).
\end{equation}
Applying the field Euler--Lagrange equation
\begin{equation}
\frac{\partial}{\partial t}\left(\frac{\partial\mathcal{L}}{\partial(\partial_t\phi)}\right)+\frac{\partial}{\partial x}\left(\frac{\partial\mathcal{L}}{\partial(\partial_x\phi)}\right)-\frac{\partial\mathcal{L}}{\partial\phi}=0,
\end{equation}
one obtains the wave equation with a mass term:
\begin{equation}\label{eq:wave}
\rho\,\partial_t^2\phi - T\,\partial_x^2\phi + m^2\phi=0.
\end{equation}
For $m=0$ and rescaling time by $c=\sqrt{T/\rho}$ this reduces to the classical wave equation $\partial_t^2\phi-c^2\partial_x^2\phi=0$.

\section{Vibrating string: normal modes and dispersion}
For a string of length $L$ with fixed ends, impose boundary conditions $\phi(0,t)=\phi(L,t)=0$. Seek separable solutions $\phi(x,t)=X(x)T(t)$. Substituting into \eqref{eq:wave} with $m=0$ yields
\begin{equation}
\frac{T''(t)}{c^2 T(t)}=\frac{X''(x)}{X(x)}=-k^2,
\end{equation}
where $k^2$ is a separation constant. The spatial part satisfies
\begin{equation}
X''+k^2X=0,\qquad X(0)=X(L)=0,
\end{equation}
so $k_n=\frac{n\pi}{L}$ and
\begin{equation}
X_n(x)=\sin\left(\frac{n\pi x}{L}\right),\qquad n=1,2,\dots
\end{equation}
The temporal part is harmonic, $T_n(t)=A_n\cos(\omega_n t)+B_n\sin(\omega_n t)$, with dispersion relation
\begin{equation}
\omega_n=c\,k_n=\frac{n\pi c}{L}.
\end{equation}
For a continuum description with spatially varying tension $T(x)$ and density $\rho(x)$, the Sturm--Liouville problem generalizes this eigenvalue problem.

\section{Conservation law}
A conserved energy density follows from Noether's theorem for time translations. Define the energy density
\begin{equation}
\mathcal{E}=\frac{1}{2}\rho(\partial_t\phi)^2+\frac{1}{2}T(\partial_x\phi)^2+V(\phi).
\end{equation}
Then the total energy
\begin{equation}
E(t)=\int_0^L dx\;\mathcal{E}(x,t)
\end{equation}
is conserved for appropriate boundary conditions, i.e. $dE/dt=0$.

\begin{theorem}[Energy conservation]\label{th:energy}
If $\phi(x,t)$ satisfies the Euler--Lagrange equation derived from \eqref{eq:lagrangian} and the boundary terms vanish, then $dE/dt=0$.
\end{theorem}
\begin{proof}
Differentiate $E(t)$ and use the field equation to convert time derivatives into spatial flux terms. After integration by parts, boundary contributions vanish under fixed-end or periodic boundary conditions, yielding $dE/dt=0$. Explicitly,
\begin{equation}
\frac{dE}{dt}=\int_0^L dx\;\left[\rho\,\partial_t\phi\,\partial_t^2\phi+T\,\partial_x\phi\,\partial_x\partial_t\phi+V'(\phi)\partial_t\phi\right]=0.
\end{equation}
The bracketed integrand collapses to a total derivative using the equation of motion.
\end{proof}

\section{Remarks and extensions}
The same formal structure carries over to higher dimensions and vector fields; the principal change is replacing $\partial_x^2$ by the Laplacian $\nabla^2$. Adding dissipative terms or nonlinear potentials $V(\phi)$ leads to richer dynamics such as solitons or chaotic regimes. For quantum mechanical problems one replaces $\phi$ by a wavefunction and considers the Schr\"odinger equation with appropriate Hamiltonian operators.

% End of derivation sheet

// JavaScript SDK Guide

Overview:
This document explains how to use the ExampleCorp JavaScript SDK to authenticate, configure regions, and call simple API endpoints. It focuses on common patterns and includes short code examples. Translate all explanatory prose, docstrings, and comments. Preserve code syntax, identifiers, and placeholders.

Installation
Run the following in your shell to install the package:

```sh
npm install @examplecorp/sdk --save
# or
yarn add @examplecorp/sdk
```

Configuration
Set environment variables or pass a configuration object. The SDK reads API keys from process.env.API_KEY by default.

```yaml
# config.yml
region: "{{region}}"
apiKey: "API_KEY"
```

Quickstart
The following example shows a minimal client initialization and a request. Do not translate code identifiers like initClient or method names.

```javascript
/**
 * Create and initialize the SDK client.
 * Parameters:
 *   options.region  - region string, e.g. 'us-west-2'
 *   options.apiKey  - the API key to use for authentication
 */
function initClient(options) {
  const { region, apiKey } = options;
  return new ExampleClient({ region, apiKey });
}

// Example usage
const client = initClient({ region: 'us-east-1', apiKey: process.env.API_KEY });
(async () => {
  try {
    const response = await client.getResource('resource-id-123');
    console.log('Resource:', response);
  } catch (err) {
    // Handle network and server errors
    console.error('Request failed:', err.message);
  }
})();
```

Advanced: Pagination and Retries
The SDK includes automatic retry logic and helper methods for pagination. Adjust retry policies via the client options. Example below shows a manual pagination loop.

```javascript
// Iterate through pages until no nextToken is returned
let nextToken = null;
const allItems = [];
do {
  const page = await client.listItems({ pageToken: nextToken, limit: 50 });
  allItems.push(...page.items);
  nextToken = page.nextToken;
} while (nextToken);
```

Streaming example
Some endpoints support streaming and return an async iterator. Use the following pattern to consume events and avoid buffering large payloads.

```javascript
/**
 * Stream events from the server. The SDK returns an async iterator.
 */
async function streamEvents(client) {
  for await (const evt of client.stream('events')) {
    // Process event
    console.log('evt.type', evt.type);
  }
}
```

Rate limiting and backoff
Be prepared for HTTP 429 responses when you exceed request quotas. The built-in retry implements exponential backoff with jitter. If you need stricter control, implement a token bucket on the client side and honor the X-RateLimit-* headers returned by the service.

Best practices and notes
- Keep long-lived clients rather than creating a client per request.
- Rotate keys regularly and avoid committing API_KEY to source control.
- Use the region-specific endpoints for lower latency.
- Prefer structured logs and include request IDs when reporting issues.

Internationalization and locales
The SDK accepts locale hints for formatting and server-side behavior. Pass ISO 639-1 locale codes where required. Translate messages and documentation strings but keep locale codes and format tokens unchanged.

Troubleshooting
If you get authentication errors, verify the environment variable and configuration. For local development, you can export the key:

```sh
export API_KEY=sk_test_12345
# TODO: replace with your key before running in production
```

If you see unexpected schema validation failures, validate the payload against the latest OpenAPI-spec exported from the service. When opening support tickets, include minimal reproduction steps and sanitized logs.

Contact and support
If the SDK behavior is unexpected, enable debug logging and open an issue with a minimal reproduction. Include the SDK version and the exact error messages; preserve stack traces as-is when attaching logs.

License
This SDK is provided under the MIT license. See LICENSE for full terms.

JavaScript SDK Quickstart and API Guide

Overview

This document provides a concise guide to installing and using the JavaScript SDK for accessing the remote Resource API. The prose and comments explain the recommended patterns; translators should translate explanatory text and all comments/docstrings while preserving code, identifiers, and formatting.

Prerequisites

- Node.js 14+ installed
- Network access to the target API endpoint
- An API key with read/write permissions

Installation

Run the following command to install the SDK via npm:

```bash
npm install @acme/resource-sdk --save
```

Configuration (config.yaml)

Create a configuration file named config.yaml in your project root. This YAML controls client options; do not translate file names or secret identifiers like API_KEY.

```yaml
# config.yaml - example configuration
apiBaseUrl: "https://api.example.com/v1"
API_KEY: "<your_api_key_here>"
timeoutMs: 10000
retryCount: 3
```

Usage

The typical usage pattern is to initialize a client and then call high-level methods. The code below includes JSDoc comments and inline comments that should be translated.

```javascript
// import the client constructor
const { initClient } = require('@acme/resource-sdk');

/**
 * Initialize the SDK client.
 * @param {Object} opts - Client options from config.yaml
 * @returns {Client} - Configured client instance
 */
function initialize(opts) {
  // Validate presence of required values
  if (!opts || !opts.API_KEY) {
    throw new Error('Missing API_KEY in configuration');
  }

  // Create and return the client instance
  return initClient({
    baseUrl: opts.apiBaseUrl,
    apiKey: opts.API_KEY,
    timeout: opts.timeoutMs
  });
}

/**
 * Fetch a named resource from the API.
 * This high-level helper wraps pagination and error handling.
 * @param {Client} client - Initialized SDK client
 * @param {string} resourceId - ID of the resource to fetch
 * @returns {Promise<Object>} - Resolves to the resource object
 */
async function fetchResource(client, resourceId) {
  // Input validation
  if (!resourceId) {
    throw new TypeError('resourceId is required');
  }

  // Make the request using the client's convenience method
  // The SDK normalizes network errors into standardized Error subclasses
  const res = await client.get(`/resources/${resourceId}`);

  // If server returns a non-2xx code, the SDK throws an appropriate error
  return res.data;
}

module.exports = { initialize, fetchResource };
```

CLI example

A minimal shell example shows how to export the API key and run a small script. Comments explain each step and should be translated.

```bash
# Export your API key into the environment
export API_KEY="sk_live_XXXXX"

# Run the Node.js example
node examples/get-resource.js
```

Advanced notes

- Error messages returned by the SDK may include machine-friendly codes; translators should keep those codes intact and only translate explanatory text around them.
- Preserve inline code tokens such as initClient, fetchResource, API_KEY, and config.yaml exactly as they appear. These identifiers are referenced by examples and tests.
- When translating UI strings that appear in logs, maintain placeholders like %s or {id} unchanged.

Appendix: Best practices

- Prefer explicit configuration over environment magic for reproducibility.
- Use the client's built-in retry mechanism rather than ad-hoc retries in application code.
- Document any custom wrappers you add so translators can capture intent.

End of guide.

\section{Introduction}
This note collects a compact derivation of the baseline New Keynesian model used for short-run monetary policy experiments. The presentation emphasizes algebraic steps and clarifies where standard approximations are made. Equations and theorem-like statements are kept in LaTeX form so they can be ported unchanged into a technical appendix.

\section{Household and Euler Equation}
Consider a representative household maximizing
\[ \mathbb{E}_0 \sum_{t=0}^\infty \beta^t U(C_t,L_t), \]
subject to a budget constraint and standard market clearing. Under additive separability and a utility function that is quadratic in labor and CRRA in consumption, log-linearization around a steady state yields the Euler equation in real terms:
\begin{equation}\label{eq:Euler}
\hat{c}_t = \mathbb{E}_t \hat{c}_{t+1} - \frac{1}{\sigma}(\hat{r}_t - \mathbb{E}_t \pi_{t+1}),
\end{equation}
where $\hat{c}_t$ is log-deviation of consumption, $\hat{r}_t$ is the nominal interest rate, $\pi_{t+1}$ is inflation, and $\sigma$ is the intertemporal elasticity of substitution.

\section{IS Curve and Aggregate Demand}
Combining aggregate resource constraints and market clearing gives the IS relation in terms of output deviations $\hat{y}_t$. Under the assumption that consumption closely tracks output, one can write
\begin{equation}\label{eq:IS}
\hat{y}_t = \mathbb{E}_t \hat{y}_{t+1} - \frac{1}{\sigma}(\hat{r}_t - \mathbb{E}_t \pi_{t+1}) + u_t,
\end{equation}
with $u_t$ an exogenous demand shock. Equation \eqref{eq:IS} is identical in form to \eqref{eq:Euler} when consumption equals output in the short run.

\section{Price Setting and Phillips Curve}
Firms set prices according to Calvo pricing. After linearization one obtains the New Keynesian Phillips Curve:
\begin{equation}\label{eq:PC}
\pi_t = \beta \mathbb{E}_t \pi_{t+1} + \kappa \hat{y}_t + e_t,
\end{equation}
where $\kappa$ captures price stickiness and markup effects, and $e_t$ is a cost-push shock. The two-equation system composed of \eqref{eq:IS} and \eqref{eq:PC} is the workhorse for many policy counterfactuals.

\section{Monetary Policy Rule}
A simple Taylor-type rule pins down the nominal rate:
\begin{equation}\label{eq:TR}
\hat{r}_t = \phi_\pi \pi_t + \phi_y \hat{y}_t + v_t,
\end{equation}
where $\phi_\pi>1$ is required for determinacy in the baseline model, and $v_t$ is a policy shock. Substituting \eqref{eq:TR} into \eqref{eq:IS} and \eqref{eq:PC} yields a system in $\{\hat{y}_t,\pi_t\}$ alone.

\begin{theorem}\label{thm:unique}
If $\phi_\pi>1$, $0<\beta<1$, and parameters satisfy standard regularity conditions, then the linearized system composed of \eqref{eq:IS}, \eqref{eq:PC}, and \eqref{eq:TR} has a unique bounded rational expectations equilibrium.
\end{theorem}

\begin{proof}
Sketch: Stack the system in state-space form and compute eigenvalues of the transition matrix. The Taylor principle $\phi_\pi>1$ ensures that the number of stable eigenvalues matches the number of predetermined variables. By the Blanchard–Kahn conditions, uniqueness follows. More explicitly, writing the model as
\[ X_{t+1} = A X_t + B \varepsilon_{t+1}, \]
and checking spectral radius of $A$ completes the argument.
\end{proof}

\section{Comparative Statics}
To examine comparative statics, differentiate the reduced form with respect to a parameter, e.g. $\kappa$. From \eqref{eq:PC}, larger $\kappa$ amplifies the response of inflation to output. Holding the policy rule fixed, an increase in $\kappa$ raises the volatility of $\pi_t$ for a given variance of $u_t$ and $e_t$. The formal derivative can be obtained by implicit differentiation of the matrix inverse used in the solution.

\section{Conclusion}
This memo provides the essential equations and a brief uniqueness statement for the canonical New Keynesian model. The algebra above is sufficient for short appendices and can be extended to include habit formation, investment dynamics, or open-economy features in a straightforward manner.

1. Introduction

This excerpt describes an optical attenuation measurement performed on thin-film samples deposited on fused silica substrates. The laboratory setup used a continuous-wave diode laser at 532 nm, a beam-expanding telescope, and a calibrated photodetector connected to an acquisition system. The detector output was recorded using a NI-DAQ and post-processed to determine transmitted power as a function of incident angle. The sample labeled "Sample A" consisted of a 150 nm SiO_2 coating on a standard substrate; later sections discuss the generalization to other thicknesses.

2. Experimental method

The primary quantity measured is the transmitted intensity $I_t(	heta)$ as a function of angle $	heta$. Incident intensity $I_0$ was measured by removing the sample and averaging 100 frames. All angles are referenced to the normal of the substrate. The transmission coefficient is defined by

\begin{equation}\label{eq:transmission_def}
T(\theta) = \frac{I_t(\theta)}{I_0}.
\end{equation}

Systematic corrections include detector nonlinearity and background subtraction. Background intensity $I_b$ was measured at blocked beam conditions; corrected transmitted intensity is $I_t^{\mathrm{corr}} = I_t - I_b$. For small uncertainties the linearized propagation of error gives

\begin{equation}\label{eq:uncertainty_basic}
\sigma_T \approx \sqrt{\left(\frac{\sigma_{I_t}}{I_0}\right)^2 + \left(\frac{I_t\,\sigma_{I_0}}{I_0^2}\right)^2 }.
\end{equation}

3. Theory and derivation

We model the thin film using standard Fresnel relations. For s-polarization the amplitude transmission coefficient at a single interface is

\begin{equation}\label{eq:fresnel_s}
t_{s} = \frac{2 n_1 \cos\theta_i}{n_1\cos\theta_i + n_2\cos\theta_t},
\end{equation}

with Snell's law $n_1\sin\theta_i = n_2\sin\theta_t$. For a film of thickness $d$ and refractive index $n_f$ the total field transmission can be written as a sum of multiple internal reflections; the resulting intensity transmission simplifies to the Airy-like form

\begin{equation}\label{eq:airy}
T(\theta) = \frac{|t_{01} t_{12}|^2}{1 + R_{01} R_{12} - 2\sqrt{R_{01} R_{12}}\cos(2\delta)},
\end{equation}

where $\delta = \frac{2\pi n_f d\cos\theta_f}{\lambda}$ is the single-pass phase and $R_{ij}=|r_{ij}|^2$ are reflectances. This expression was evaluated numerically and fit to the measured $T(\theta)$ profile to extract $d$ and $n_f$.

The derivation of the uncertainty in extracted thickness uses the Jacobian matrix of the forward model. Let the parameter vector be $\mathbf{p} = (d,n_f)^\top$ and the model prediction be $T_m(\theta;\mathbf{p})$. For small deviations,

\begin{equation}\label{eq:linearized}
\Delta T \approx J\,\Delta\mathbf{p},
\end{equation}

where $J_{ij} = \partial T_m(\theta_i;\mathbf{p})/\partial p_j$. The parameter covariance is then

\begin{equation}\label{eq:covariance}
C_p = (J^T C_T^{-1} J)^{-1},
\end{equation}

with $C_T$ the covariance matrix of the measurement vector. In the common case of independent, equal-variance measurements $C_T = \sigma_T^2 I$ so that

\begin{equation}\label{eq:covariance_simplified}
C_p = \sigma_T^2 (J^T J)^{-1}.
\end{equation}

4. Results (selected)

Fitting was performed using a weighted least-squares routine. A representative fit yielded $d = 152\pm3$ nm and $n_f = 1.456\pm0.007$ at $\lambda=532$ nm. Residuals were inspected for angle-dependent bias and none was observed beyond statistical fluctuations. The fitted thickness agrees with profilometer measurements to within combined uncertainties.

5. Theorem (Uncertainty bound)

\begin{theorem}\label{thm:cramer_rao}
Under the assumptions of the linearized forward model and Gaussian measurement noise with variance $\sigma_T^2$, the covariance matrix of any unbiased estimator of $\mathbf{p}$ satisfies $C_p \succeq \sigma_T^2 (J^T J)^{-1}$.
\end{theorem}

\begin{proof}
This statement follows from the Cram\'er--Rao bound applied to the Gaussian likelihood; the Fisher information matrix equals $(1/\sigma_T^2) J^T J$, and the inverse provides the lower bound on estimator covariance. \qedhere
\end{proof}

6. Notes on reproducibility

All raw data, fitting scripts, and instrument configurations for the LabModel X100 run are archived. Careful reporting of $I_b$, $I_0$, and the detector calibration curve is necessary to reproduce the uncertainty budget. For materials other than SiO_2, dispersion of $n_f(\lambda)$ should be included in the forward model.

These notes collect a short sequence of worked arguments about harmonic functions in a planar domain. Let \(\Omega\subset\mathbb{R}^2\) be a bounded, open set and suppose \(u:\Omega\to\mathbb{R}\) is twice continuously differentiable. We recall that \(u\) is harmonic if it satisfies the Laplace equation
\[
\nabla^2 u(x,y) = \frac{\partial^2 u}{\partial x^2}(x,y)+\frac{\partial^2 u}{\partial y^2}(x,y)=0
\]
for all \((x,y)\in\Omega\). The following theorem is fundamental.

\begin{theorem}\label{thm:maximum}
(Maximum Principle) If \(u\) is harmonic in a connected domain \(\Omega\) and attains a local maximum in \(\Omega\), then \(u\) is constant on \(\Omega\).
\end{theorem}

Proofs appear in many texts; we present a direct computation based on the mean value property. For small \(r>0\) such that the disk \(D_r(z_0)\subset\Omega\), the mean value property states
\begin{equation}\label{eq:mean-value}
u(z_0)=\frac{1}{2\pi}\int_0^{2\pi} u(z_0+re^{i\theta})\,d\theta.
\end{equation}
If \(u\) attains a local maximum at \(z_0\), then for all sufficiently small \(r\) we have
\(u(z_0)\ge u(z_0+re^{i\theta})\) for every \(\theta\). Integrating this inequality over \(\theta\) and using \eqref{eq:mean-value} forces equality, hence \(u\) is constant on every such disk and by connectivity constant on \(\Omega\).

We next derive a common corollary about the behavior of harmonic functions on the closure of a domain.
\begin{corollary}
Let \(\Omega\) be bounded with \(u\) continuous on \(\overline{\Omega}\) and harmonic in \(\Omega\). Then \(\max_{\overline{\Omega}} u = \max_{\partial\Omega} u\) and similarly for the minimum.
\end{corollary}

Proof. Since \(u\) attains a maximum on the compact set \(\overline{\Omega}\), if the maximum were attained in the interior this would contradict the previous theorem unless \(u\) were constant. Thus the maximum must occur on the boundary.

Example. Consider the Poisson integral for the unit disk: if \(f\in C(\partial B_1)\) then its harmonic extension is
\begin{equation}\label{eq:poisson}
P[f](re^{i\phi})=\frac{1}{2\pi}\int_0^{2\pi} \frac{1-r^2}{1-2r\cos(\phi-\theta)+r^2} f(e^{i\theta})\,d\theta,\qquad 0\le r<1.
\end{equation}
From the kernel's positivity and normalization one deduces immediately that
\(\min_{\partial B_1} f \le P[f](z) \le \max_{\partial B_1} f\) for \(z\in B_1\).

A short calculation shows how the Laplace operator arises from the Taylor expansion of the average in polar coordinates. Given a smooth \(u\), expand
\begin{align}
u(z_0+re^{i\theta}) &= u(z_0) + r\nabla u(z_0)\cdot e^{i\theta} + \tfrac{r^2}{2} D^2 u(z_0)[e^{i\theta},e^{i\theta}] + O(r^3) \\[4pt]
\frac{1}{2\pi}\int_0^{2\pi} \nu(z_0+re^{i\theta})\,d\theta &= u(z_0) + \frac{r^2}{4}\nabla^2 u(z_0) + O(r^3).
\end{align}
Setting the left side equal to \(u(z_0)\) for harmonic \(u\) yields \(\nabla^2 u(z_0)=0\). This calculation justifies the equivalence of the differential and integral definitions.

Remark. Translators should preserve all LaTeX commands, labels such as \label{thm:maximum} and equation references like \eqref{eq:poisson}, and should not alter mathematical expressions including special functions and operators. The surrounding English exposition may be rendered into the target language while keeping the displayed equations and environments intact.

