\section{Introduction}
This note presents a concise derivation of the one-dimensional wave equation for a taut string, together with energy conservation and a short uniqueness theorem. The exposition keeps the calculations explicit so that each step can be followed and translated without ambiguity. We adopt the usual notation: $u(x,t)$ denotes transverse displacement, $\rho$ the linear mass density, $T$ the constant tension, and $c=\sqrt{T/\rho}$ the wave speed.

\section{Derivation of the PDE}
Consider an infinitesimal segment of string between $x$ and $x+\Delta x$. The vertical forces from tension are approximately $T\sin\theta(x+\Delta x)-T\sin\theta(x)$. For small slopes $\sin\theta\approx u_x$, and Newton's second law yields
\begin{equation}\label{eq:balance}
\rho\,\Delta x\, u_{tt} = T\bigl(u_x(x+\Delta x,t)-u_x(x,t)\bigr)+O((\Delta x)^2).
\end{equation}
Dividing by $\Delta x$ and letting $\Delta x\to 0$ gives the classical wave equation
\begin{equation}\label{eq:wave}
u_{tt}-c^2 u_{xx}=0,
\end{equation}
where $c^2=T/\rho$. Equation \eqref{eq:wave} is linear and second-order in both time and space. Initial conditions are typically
\begin{equation}\label{eq:ic}
u(x,0)=f(x),\qquad u_t(x,0)=g(x),
\end{equation}
and boundary conditions will depend on whether the ends are fixed, free, or periodic.

\section{Energy and Conservation}
Define the kinetic and potential energy densities by
\begin{align}
\mathcal{K}(x,t) &= \tfrac{1}{2}\rho\,u_t^2(x,t), \\
\mathcal{P}(x,t) &= \tfrac{1}{2}T\,u_x^2(x,t).
\end{align}
The total energy on the interval $[a,b]$ is
\begin{equation}\label{eq:energy}
E(t)=\int_a^b\bigl(\mathcal{K}(x,t)+\mathcal{P}(x,t)\bigr)\,dx.
\end{equation}
Differentiating under the integral sign and using \eqref{eq:wave} leads to the balance law
\begin{equation}\label{eq:energy_balance}
\frac{dE}{dt} = T\bigl[u_x u_t\bigr]_a^b.
\end{equation}
Hence, for fixed ends ($u(a,t)=u(b,t)=0$) or periodic boundaries, the boundary term vanishes and $E(t)$ is constant in time; energy is conserved.

\section{A Theorem on Uniqueness}
\begin{theorem}\label{thm:uniq}
Let $u$ be a sufficiently smooth solution of \eqref{eq:wave} on $[a,b]\times[0,T]$ with homogeneous Dirichlet boundary conditions $u(a,t)=u(b,t)=0$ and zero initial data $u(x,0)=u_t(x,0)=0$. Then $u\equiv 0$ on $[a,b]\times[0,T]$.
\end{theorem}
\begin{proof}
Compute the energy $E(t)$ from \eqref{eq:energy}. With the given boundary and initial conditions, \eqref{eq:energy_balance} implies $dE/dt=0$ and $E(0)=0$, hence $E(t)=0$ for all $t$. Therefore $u_t\equiv 0$ and $u_x\equiv 0$, which together with boundary values yields $u\equiv 0$.
\end{proof}

\section{Example: Gaussian Pulse Propagation}
As an instructive example, take initial displacement
\begin{equation}\label{eq:gauss}
f(x)=\exp\bigl(-\tfrac{(x-x_0)^2}{2\sigma^2}\bigr),\qquad g(x)=0.
\end{equation}
The d'Alembert formula on the whole line gives
\begin{equation}\label{eq:dalembert}
u(x,t)=\tfrac{1}{2}\bigl(f(x-ct)+f(x+ct)\bigr) + \tfrac{1}{2c}\int_{x-ct}^{x+ct} g(s)\,ds.
\end{equation}
With $g\equiv 0$ the pulse splits into two traveling copies of the Gaussian moving at speeds $\pm c$. The $L^2$-norm of $u$ remains bounded and energy computed from \eqref{eq:energy} is constant.

\section{Concluding Remarks}
The calculations above are standard but showcase the necessary interplay between physical assumptions (small slope, constant tension) and analytical consequences (energy conservation, uniqueness). For further study, one can add damping terms, external forcing, or consider variable coefficients $T(x)$ and $\rho(x)$, which complicate the conservation laws and require weighted energy estimates.

