\section{Introduction}
This extract presents methods and derivations used to estimate the diffusion coefficient $D$ from concentration measurements in a one-dimensional experimental cell. The primary model is the linear diffusion equation
\begin{equation}\label{eq:diffusion}
\frac{\partial C(x,t)}{\partial t} = D\nabla^2 C(x,t),
\end{equation}
where $C(x,t)$ denotes concentration, $x$ is the spatial coordinate, and $t$ denotes time. For a point-source initial condition the analytical solution in an infinite domain is the Gaussian
\begin{equation}\label{eq:gaussian_solution}
C(x,t) = \frac{M}{\sqrt{4\pi D t}}\exp\left(-\frac{x^2}{4Dt}\right),
\end{equation}
with total mass $M$ preserved.

\section{Methods}
The experimental setup is sketched in Figure~\ref{fig:setup}. We record concentration profiles at a sequence of times $t_k$ and perform nonlinear least-squares fitting of the form
\begin{equation}\label{eq:fit_model}
C_{\mathrm{fit}}(x;t_k) = A_k\exp\left(-\frac{(x-x_0)^2}{4D t_k}\right) + B_k,
\end{equation}
where $A_k$, $B_k$, and $x_0$ are fit parameters and $D$ is assumed constant across all times. The fit minimizes
\begin{equation}
\chi^2(D,\{A_k,B_k\}) = \sum_{k,i} \frac{\bigl(C_{\mathrm{meas}}(x_i,t_k)-C_{\mathrm{fit}}(x_i;t_k)\bigr)^2}{\sigma_{k,i}^2}.
\end{equation}
To reduce correlation between amplitude and $D$ we reparameterize by taking the second moment of measured profiles:
\begin{equation}\label{eq:second_moment}
\mu_2(t) = \frac{\int x^2 C(x,t)\,dx}{\int C(x,t)\,dx} = 2Dt + \mu_2(0),
\end{equation}
which leads to a linear regression for $\mu_2(t)$ versus $t$.

\begin{figure}[ht]
\centering
% schematic placeholder
\caption{Schematic of the one-dimensional cell and sensor array used to acquire concentration profiles.}
\label{fig:setup}
\end{figure}

\section{Derivation of Moment Relation}
Starting from Eq.~\eqref{eq:diffusion}, multiply both sides by $x^2$ and integrate over $x$. Using integration by parts and assuming vanishing boundary terms at infinity, one finds
\begin{align}\label{eq:moment_derivation}
\frac{d}{dt}\int x^2 C\,dx &= D\int x^2 \nabla^2 C\,dx \nonumber \\
&= D\left[\int \nabla\cdot(x^2\nabla C)\,dx - 2\int x\partial_x C\,dx\right] \nonumber \\
&= -2D\int x\partial_x C\,dx = 2D \int C\,dx,
\end{align}
where we used $\int x\partial_x C\,dx = -\int C\,dx$ after integration by parts. Dividing by total mass $M=\int C\,dx$ yields Eq.~\eqref{eq:second_moment}.

\section{Stability and Error Bounds}
The following theorem gives a practical stability criterion for the linear regression used to extract $D$.
\begin{theorem}[Stability Criterion]\label{thm:stability}
Suppose measurements of $\mu_2(t_k)$ are obtained with independent Gaussian errors of variance $\sigma_k^2$. If the sampling times $t_k$ span an interval of length $T$ and are not clustered, then the least-squares estimate of $D$ has variance bounded by
\begin{equation}
\mathrm{Var}(\hat D) \leq \frac{\max_k \sigma_k^2}{2M^2\sum_k (t_k-\bar t)^2} \leq \frac{\max_k \sigma_k^2}{2M^2 N(\Delta t)^2},
\end{equation}
where $\bar t$ is the sample mean of $t_k$, $N$ is the number of time points, and $\Delta t\approx T/N$.
\end{theorem}

The theorem is proved by standard formulas for linear regression and propagation of independent measurement errors; the factor of $2$ appears because $\mu_2(t)=2Dt+\mu_2(0)$.

\section{Results and Discussion}
In our lab example, fitting second moments from five time snapshots produced $\hat D=(1.25\pm0.05)\times10^{-9}\,\mathrm{m^2\,s^{-1}}$, consistent with independent tracer experiments. Systematic errors arise mainly from baseline subtraction $B_k$ and finite-domain corrections omitted in Eq.~\eqref{eq:gaussian_solution}. For translation, note that units and symbols must be preserved exactly and that inline and display mathematics (for example $\mu_2$, $\nabla^2$, and Eq.~\eqref{eq:diffusion}) should not be altered.

\section{Introduction}
This note provides a proof outline for a variational estimate used in elliptic problems on bounded domains. The presentation emphasizes the structure of the argument: functional setting, coercivity, a priori estimates, and the key energy identity. We keep the exposition self-contained and focus on the steps that a translator must preserve verbatim, namely the LaTeX math, labels, and environment names.

\section{Setup and Main Statement}
Let $\Omega\subset\mathbb{R}^n$ be a bounded domain with smooth boundary. We consider a bilinear form $a(\cdot,\cdot)$ on $H^1(\Omega)$ satisfying the coercivity condition
\begin{equation}\label{eq:coercive}
  a(u,u) \ge \alpha \|u\|_{H^1(\Omega)}^2 - \beta \|u\|_{L^2(\Omega)}^2
\end{equation}
for constants $\alpha>0$ and $\beta\ge 0$. Let $L$ be a bounded linear functional on $H^1(\Omega)$. We aim to show existence of a solution $u\in H^1(\Omega)$ to the variational equation
\begin{equation}\label{eq:variational}
  a(u,v) = L(v) \quad\text{for all } v\in H^1(\Omega).
\end{equation}

\begin{theorem}\label{thm:main}
Assume \eqref{eq:coercive} and that $L\in H^{-1}(\Omega)$. Then there exists a unique solution $u\in H^1(\Omega)$ to \eqref{eq:variational} and the solution satisfies the a priori bound
\begin{equation}\label{eq:apriori}
  \|u\|_{H^1(\Omega)} \le C\,\|L\|_{H^{-1}(\Omega)},
\end{equation}
for some constant $C=C(\alpha,\beta,\Omega)$.
\end{theorem}

\begin{proof}[Proof outline]
The proof follows three steps: approximation, coercivity-based estimate, and limit passage.

1. \emph{Galerkin approximation.} Choose a sequence of finite-dimensional subspaces $V_k\subset H^1(\Omega)$ with $\bigcup_k V_k$ dense in $H^1(\Omega)$. For each $k$ solve
\begin{equation}\label{eq:galerkin}
  a(u_k,v) = L(v) \quad\text{for all } v\in V_k.
\end{equation}
Existence in a finite-dimensional setting is trivial by linear algebra.

2. \emph{Uniform a priori estimate.} Testing \eqref{eq:galerkin} with $v=u_k$ yields the energy identity
\begin{equation}\label{eq:energy}
  a(u_k,u_k) = L(u_k).
\end{equation}
Using coercivity \eqref{eq:coercive} and the duality bound $L(u_k) \le \|L\|_{H^{-1}}\,\|u_k\|_{H^1}$ we obtain
\begin{align}
  \alpha \|u_k\|_{H^1}^2 - \beta \|u_k\|_{L^2}^2 &\le \|L\|_{H^{-1}}\,\|u_k\|_{H^1} \\
  &\le \frac{\alpha}{2} \|u_k\|_{H^1}^2 + \frac{1}{2\alpha} \|L\|_{H^{-1}}^2.
\end{align}
Rearranging and absorbing terms gives a uniform bound of the form \eqref{eq:apriori} for $u_k$ independent of $k$.

3. \emph{Compactness and limit.} From the uniform bound and Rellich's theorem we extract a subsequence (still denoted $u_k$) with $u_k\rightharpoonup u$ in $H^1(\Omega)$ and strongly in $L^2(\Omega)$. Passing to the limit in \eqref{eq:galerkin} yields \eqref{eq:variational}. Uniqueness follows from coercivity by taking the difference of two solutions and testing with the difference.
\end{proof}

\section{Remarks and Extensions}
The same outline works when $a(\cdot,\cdot)$ contains lower-order terms provided they are controlled in $L^p$ spaces. For nonlinear problems one replaces linear functionals with Nemitskii operators and uses monotonicity methods; the energy identity \eqref{eq:energy} is then replaced by an inequality. A careful translator should preserve labels such as \verb|\label{eq:coercive}| and environment names exactly, while rendering the surrounding prose into the target language.

\section{Introduction}
This note collects a self-contained derivation of the Euler--Lagrange equation and a worked example illustrating its application to a classical problem. The exposition keeps the mathematical steps explicit so that translations must preserve LaTeX math, labels, and environment commands exactly. We consider functionals of the form
\begin{equation}
S[y]=\int_{x_0}^{x_1} L\big(x,y(x),y'(x)\big)\,dx,
\end{equation}
where $y\colon[x_0,x_1]\to\mathbb{R}$ is a sufficiently smooth function and $L$ is a given Lagrangian density.

\section{Derivation of the Euler--Lagrange equation}
We look for stationary points of $S$ under compactly supported variations $\eta$ with $\eta(x_0)=\eta(x_1)=0$. Define the varied curve $y_\varepsilon=y+\varepsilon\eta$ and compute the first variation:
\begin{align}
\delta S &=\left.\frac{d}{d\varepsilon} S[y_\varepsilon]\right|_{\varepsilon=0}
= \int_{x_0}^{x_1} \left(\frac{\partial L}{\partial y}\eta + \frac{\partial L}{\partial y'}\eta'\right)dx.
\label{eq:first_variation}
\end{align}
Integrating the second term by parts and using $\eta(x_0)=\eta(x_1)=0$ gives
\begin{align}
\delta S &= \int_{x_0}^{x_1} \left(\frac{\partial L}{\partial y}-\frac{d}{dx}\frac{\partial L}{\partial y'}\right)\eta\,dx.
\end{align}
Since $\eta$ is arbitrary, the integrand must vanish pointwise. This yields the Euler--Lagrange equation:
\begin{equation}
\frac{d}{dx}\frac{\partial L}{\partial y'}-\frac{\partial L}{\partial y}=0.
\label{eq:EL}
\end{equation}

\begin{theorem}
(Stationarity implies Euler--Lagrange) If $y$ is a smooth extremal of $S$ with fixed endpoints, then $y$ satisfies the Euler--Lagrange equation \eqref{eq:EL}.
\end{theorem}

\begin{proof}
The calculation leading to \eqref{eq:EL} shows that the first variation satisfies $\delta S = 0$ for all admissible $\eta$, hence the integrand in \eqref{eq:first_variation} vanishes and the claim follows.
\end{proof}

\section{Worked example: the brachistochrone}
As a concrete illustration, consider the problem of minimizing the travel time for a particle under gravity between two points in the vertical plane. Let the curve be given by $y(x)$ measured downward, and assume the particle starts at rest. The time functional is
\begin{equation}
T[y]=\int_{x_0}^{x_1} \frac{\sqrt{1+(y')^2}}{\sqrt{2g y}}\,dx,
\end{equation}
where $g$ is the gravitational constant. The Lagrangian is
\begin{equation}
L(x,y,y')=\frac{\sqrt{1+(y')^2}}{\sqrt{2g y}}.
\end{equation}
Because $L$ does not depend explicitly on $x$, the Hamiltonian-like quantity
\begin{equation}
H = y'\frac{\partial L}{\partial y'}-L
\end{equation}
is conserved. Computing $\partial L/\partial y'$ and simplifying leads to the first integral
\begin{equation}
\frac{1}{\sqrt{2g y}}\frac{1}{\sqrt{1+(y')^2}} = C,
\end{equation}
where $C>0$ is a constant. Solving for $y'$ gives
\begin{equation}
y' = \sqrt{\frac{1}{(C^2 2g y)}-1}.
\end{equation}
This differential equation can be parametrized by a cycloidal substitution, yielding the classical solution curve.

