\section*{Introduction}
This note presents a concise derivation of the one-dimensional wave equation from a variational principle, followed by a demonstration of the associated energy conservation law. The presentation emphasizes explicit steps useful for students transitioning from Lagrangian mechanics to field equations. All derivations are carried out for a real scalar field $u(x,t)$ on the domain $x\in\mathbb{R}$, $t\ge0$.

\section{Lagrangian and Euler--Lagrange Equation}
Consider the action functional
\begin{equation}\label{eq:action}
S[u]=\int_{t_0}^{t_1}\!\int_{-\infty}^{\infty} \mathcal{L}(u,u_t,u_x)\,dx\,dt,
\end{equation}
with Lagrangian density
\begin{equation}\label{eq:lagrangian}
\mathcal{L}=\frac{1}{2}\left(u_t^2 - c^2 u_x^2\right) - V(u),
\end{equation}
where $c$ is the wave speed and $V(u)$ is a potential term, possibly nonlinear. The Euler--Lagrange equation for this density gives
\begin{equation}\label{eq:EL}
\frac{\partial}{\partial t}\left(\frac{\partial\mathcal{L}}{\partial u_t}\right)+\frac{\partial}{\partial x}\left(\frac{\partial\mathcal{L}}{\partial u_x}\right)-\frac{\partial\mathcal{L}}{\partial u}=0.
\end{equation}
Substitution of \eqref{eq:lagrangian} into \eqref{eq:EL} yields the wave equation with a source from the potential,
\begin{equation}\label{eq:wave}
u_{tt}-c^2 u_{xx} + V'(u)=0.
\end{equation}
For the linear wave equation set $V(u)=0$, and one recovers $u_{tt}-c^2 u_{xx}=0$.

\section{Energy Density and Conservation}
Define the energy density $\mathcal{E}(x,t)$ and energy flux $\mathcal{F}(x,t)$ by
\begin{equation}\label{eq:energy_density}
\mathcal{E}=\frac{1}{2}\left(u_t^2 + c^2 u_x^2\right) + V(u),\qquad \mathcal{F}=-c^2 u_t u_x.
\end{equation}
A straightforward calculation using \eqref{eq:wave} gives the local conservation law
\begin{equation}\label{eq:local_conservation}
\frac{\partial\mathcal{E}}{\partial t}+\frac{\partial\mathcal{F}}{\partial x}=0.
\end{equation}
Integrating \eqref{eq:local_conservation} over a fixed interval $[a,b]$ yields the global statement
\begin{equation}\label{eq:global_energy}
\frac{d}{dt} \int_a^b \mathcal{E}(x,t)\,dx = -\left[\mathcal{F}(b,t)-\mathcal{F}(a,t)\right].
\end{equation}
In the absence of boundary flux, or for decaying fields as $|x|\to\infty$, the total energy is conserved.

\begin{theorem}\label{thm:energy}
(Conservation of Energy) For solutions of \eqref{eq:wave} with sufficiently rapid decay at spatial infinity, the total energy
\begin{equation}\label{eq:total_energy}
E(t)=\int_{-\infty}^{\infty} \mathcal{E}(x,t)\,dx
\end{equation}
is constant in time: $\dfrac{dE}{dt}=0$.
\end{theorem}

\begin{proof}
Differentiate \eqref{eq:total_energy} with respect to $t$ and use \eqref{eq:local_conservation} to write
\begin{equation*}
\frac{dE}{dt} = -\lim_{R\to\infty} \left[\mathcal{F}(R,t)-\mathcal{F}(-R,t)\right].
\end{equation*}
For fields that vanish sufficiently fast as $|x|\to\infty$, the boundary terms vanish and the result follows.
\end{proof}

\section{Example: Gaussian Pulse}
As an illustrative example, take the linear case $V\equiv0$ and initial data corresponding to a right-moving Gaussian pulse:
\begin{align}\label{eq:gaussian}
u(x,0)&=e^{-x^2/\sigma^2},\\
\partial_t u(x,0)&= -\frac{2x}{\sigma^2} e^{-x^2/\sigma^2} c.
\end{align}
The d'Alembert solution gives
\begin{equation}\label{eq:dalembert}
u(x,t)=\frac{1}{2}\left[ f(x-ct)+f(x+ct)\right],\qquad f(z)=e^{-z^2/\sigma^2}.
\end{equation}
One verifies directly that the energy computed from \eqref{eq:total_energy} is independent of $t$ by substituting \eqref{eq:dalembert} and evaluating Gaussian integrals.

\section*{Remarks}
The same variational approach extends to higher dimensions and to other second-order hyperbolic systems. Care must be taken when $V(u)$ is nonconvex, as additional phenomena such as modulational instability may appear. The conserved energy \eqref{eq:total_energy} is the starting point for many stability and scattering arguments.

