\section{Abstract}
This note develops a concise derivation of a closed-economy IS-LM model with emphasis on comparative statics. The exposition mixes informal economic intuition with formal algebra. Inline expressions such as $Y=C+I+G$ and $S=Y-C-T$ appear throughout, and the reader is expected to follow standard macroeconomic notation.

\section{Introduction}
We consider a Keynesian cross interacting with a money market. The goods market equilibrium is given by aggregate demand $AD$ and output $Y$. Consumption is assumed linear in disposable income, $C=C_0+c(Y-T)$, and investment depends negatively on the nominal interest rate $i$ according to $I=I_0-b i$. Money demand is specified as $L(Y,i)=kY-hi$ and the money supply is $\bar{M}/P$.

\section{Model and equilibrium}
The equilibrium conditions are:
\begin{equation}\label{eq:IS}
Y=C_0+c(Y-T)+I_0-b i+G
\end{equation}
for the goods market, and
\begin{equation}\label{eq:LM}
\frac{\bar{M}}{P}=kY-hi
\end{equation}
for the money market. Solving (\ref{eq:IS}) for $Y$ yields the IS relation,
\begin{equation}\label{eq:IS_LM}
Y=\frac{1}{1-c}\left(C_0+I_0+G-cT\right)-\frac{b}{1-c}i.
\end{equation}
Substituting (\ref{eq:IS_LM}) into (\ref{eq:LM}) produces the reduced-form solution for the equilibrium pair $(Y^*,i^*)$.

\subsection{Closed-form solution}
Combining the two equations leads to the system
\begin{align}
Y&=A-B i,\\
\frac{\bar{M}}{P}&=kY-hi,
\end{align}
where $A=\frac{1}{1-c}(C_0+I_0+G-cT)$ and $B=\frac{b}{1-c}$. Solving for $i^*$ we use algebraic elimination:
\begin{equation}\label{eq:i_star}
i^*=\frac{kA-\bar{M}/P}{kB+h}.
\end{equation}
Hence,
\begin{equation}\label{eq:Y_star}
Y^*=A-B i^* = A - B\frac{kA-\bar{M}/P}{kB+h}.
\end{equation}
These expressions allow comparative statics with respect to fiscal policy $G$ and real money balances $\bar{M}/P$.

\begin{theorem}
If $0<c<1$, $b>0$, $k>0$, and $h>0$, then the equilibrium $(Y^*,i^*)$ defined by (\ref{eq:i_star}) and (\ref{eq:Y_star}) is unique and locally stable under standard adaptive expectations in both markets.
\end{theorem}

\begin{proof}
Uniqueness follows from linearity: the determinants of the coefficient matrix are nonzero because $kB+h>0$. Local stability can be shown by linearizing the dynamic adjustment system
\begin{align}
\dot{Y}&=\alpha(AD(Y,i)-Y),\\
\dot{i}&=\beta(L(Y,i)-\bar{M}/P),
\end{align}
and verifying that the eigenvalues of the Jacobian have negative real parts for $\alpha,\beta>0$. The Jacobian is
\begin{equation}
J=\begin{pmatrix}
\alpha(c-1) & -\alpha b \\
\beta k & -\beta h
\end{pmatrix}.
\end{equation}
Its trace is $\alpha(c-1)-\beta h$ and determinant is $\alpha\beta[(1-c)h-bk]>0$, which implies local stability when both trace and determinant conditions hold for given adjustment speeds.
\end{proof}

\section{Comparative statics}
Differentiating (\ref{eq:i_star}) yields the responses
\begin{equation}
\frac{\partial i^*}{\partial G}=\frac{k}{kB+h}\frac{\partial A}{\partial G}=\frac{k}{kB+h}\frac{1}{1-c},
\end{equation}
showing that fiscal expansion raises the interest rate; similarly
\begin{equation}
\frac{\partial Y^*}{\partial (\bar{M}/P)}=\frac{B}{kB+h}>0,
\end{equation}
so an increase in real money balances raises output.

