\begin{document}
\title{Derivation of the Electromagnetic Wave Equation and Energy Conservation}
\author{Prepared for advanced undergraduate physics}
\maketitle

\section{Introduction}
This note derives the electromagnetic wave equation in free space starting from Maxwell's equations and then states a simple energy conservation theorem (Poynting theorem) with its local differential form. The goal is to provide a concise, self-contained derivation suitable for classroom exposition. The fields are denoted by $\mathbf{E}(\mathbf{r},t)$ and $\mathbf{B}(\mathbf{r},t)$; when discussing a single Cartesian component we write $E(x,t)$ for brevity.

\section{From Maxwell to the wave equation}\label{sec:wave}
Starting with Maxwell's equations in vacuum (SI units) we have
\begin{equation}
\nabla\cdot\mathbf{E}=0, \qquad \nabla\cdot\mathbf{B}=0,
\end{equation}
\begin{equation}
\nabla\times\mathbf{E}=-\frac{\partial\mathbf{B}}{\partial t}, \qquad \nabla\times\mathbf{B}=\mu_0\varepsilon_0\frac{\partial\mathbf{E}}{\partial t}.
\end{equation}
Taking the curl of Faraday's law gives
\begin{equation}
\nabla\times(\nabla\times\mathbf{E})=-\frac{\partial}{\partial t}(\nabla\times\mathbf{B})=-\mu_0\varepsilon_0\frac{\partial^2\mathbf{E}}{\partial t^2}.
\end{equation}
Using the vector identity $\nabla\times(\nabla\times\mathbf{E})=\nabla(\nabla\cdot\mathbf{E})-\nabla^2\mathbf{E}$ and $\nabla\cdot\mathbf{E}=0$, we obtain the homogeneous vector wave equation
\begin{equation}\label{eq:wave}
\nabla^2\mathbf{E}-\mu_0\varepsilon_0\frac{\partial^2\mathbf{E}}{\partial t^2}=0.
\end{equation}
An identical equation holds for $\mathbf{B}$. For a single component such as $E(x,t)$ in one spatial dimension this reduces to
\begin{equation}
\frac{\partial^2 E}{\partial x^2}-\frac{1}{c^2}\frac{\partial^2 E}{\partial t^2}=0, \quad c=\frac{1}{\sqrt{\mu_0\varepsilon_0}}.
\end{equation}
This is the canonical second-order wave equation supporting left- and right-propagating solutions.

\subsection{Plane wave solution}
Assume a monochromatic plane wave ansatz
\begin{equation}
\mathbf{E}(\mathbf{r},t)=\mathbf{E}_0 e^{i(\mathbf{k}\cdot\mathbf{r}-\omega t)}.
\end{equation}
Inserting into equation \eqref{eq:wave} yields the dispersion relation $\omega^2=c^2|\mathbf{k}|^2$, confirming propagation at speed $c$.

\section{Energy: Poynting theorem}
We next derive the local form of energy conservation for the electromagnetic field. Define the energy density
\begin{equation}\label{eq:energy}
u=\frac{1}{2}\left(\varepsilon_0|\mathbf{E}|^2+\frac{1}{\mu_0}|\mathbf{B}|^2\right)
\end{equation}
and the Poynting vector
\begin{equation}
\mathbf{S}=\frac{1}{\mu_0}\mathbf{E}\times\mathbf{B}.
\end{equation}

\begin{theorem}[Poynting theorem]\label{thm:poynting}
In vacuum, the electromagnetic energy density and Poynting flux satisfy the local conservation law
\begin{equation}
\frac{\partial u}{\partial t}+\nabla\cdot\mathbf{S}=0.
\end{equation}
\end{theorem}

\begin{proof}
Compute $\mathbf{E}\cdot(\nabla\times\mathbf{B})-\mathbf{B}\cdot(\nabla\times\mathbf{E})$ using Maxwell's equations to obtain
\[\varepsilon_0\mathbf{E}\cdot\frac{\partial\mathbf{E}}{\partial t}+\frac{1}{\mu_0}\mathbf{B}\cdot\frac{\partial\mathbf{B}}{\partial t}+\nabla\cdot\mathbf{S}=0.\]
This can be rearranged into the advertised form by recognizing the time derivative of $u$ in \eqref{eq:energy}.
\end{proof}

\section{Example: Gaussian pulse}
Consider a Gaussian pulse in one dimension: $E(x,0)=E_0e^{-x^2/\sigma^2}$ and $\partial_tE(x,0)=0$. The solution decomposes into two pulses moving at $\pm c$ and the total energy, obtained by integrating $u$ over $x$, is conserved as expected from the theorem.

\section{Conclusion}
We have shown how Maxwell's equations lead directly to the wave equation and stated the local energy conservation result. The derivation emphasizes the role of vector identities and the physical interpretation of the Poynting vector as energy flux.

