\section*{Abstract}
These notes derive key properties of solutions to the linear wave equation in a bounded domain. We present a short derivation of the energy identity, prove conservation of energy in the homogeneous case, and illustrate with a separated-variables example in one spatial dimension. The exposition keeps formulas explicit so that the LaTeX display and inline mathematics are preserved.

\section{Introduction}
Consider the classical wave equation for a scalar field $u=u(x,t)$ on a domain $\Omega\subset\mathbb{R}^n$ with smooth boundary $\partial\Omega$:
\begin{equation}\label{eq:wave}
u_{tt}-c^2\Delta u = 0, \qquad (x,t)\in\Omega\times(0,T),
\end{equation}
subject to homogeneous Dirichlet boundary conditions $u|_{\partial\Omega}=0$ and initial data $u(x,0)=u_0(x)$, $u_t(x,0)=v_0(x)$. Here $c>0$ denotes the wave speed. We will write $\langle f,g\rangle=\int_\Omega f(x)g(x)\,dx$ for the $L^2(\Omega)$ inner product.

\section{Derivation of the energy identity}
Multiply \eqref{eq:wave} by $u_t$ and integrate over $\Omega$ to obtain
\begin{equation}\label{eq:energy_deriv}
\int_\Omega u_{tt}u_t\,dx - c^2\int_\Omega \Delta u\,u_t\,dx = 0.
\end{equation}
The first term is the time derivative of the kinetic energy density, since
\begin{equation}\label{eq:kinetic}
\int_\Omega u_{tt}u_t\,dx = \frac{1}{2}\frac{d}{dt}\int_\Omega (u_t)^2\,dx.
\end{equation}
Integrating the second term by parts and using $u|_{\partial\Omega}=0$ gives
\begin{equation}\label{eq:potential}
-\int_\Omega \Delta u\,u_t\,dx = \int_\Omega \nabla u\cdot\nabla u_t\,dx = \frac{1}{2}\frac{d}{dt}\int_\Omega |\nabla u|^2\,dx.
\end{equation}
Combining \eqref{eq:energy_deriv}--\eqref{eq:potential} yields the energy identity
\begin{equation}\label{eq:energy}
\frac{d}{dt}E(t)=0, \qquad E(t):=\frac{1}{2}\int_\Omega\bigl((u_t)^2 + c^2|\nabla u|^2\bigr)\,dx.
\end{equation}
Thus $E(t)=E(0)$ for all $t$ for which the solution exists.

\begin{theorem}[Energy conservation]\label{thm:energy}
Let $u$ be a sufficiently smooth solution of \eqref{eq:wave} with homogeneous Dirichlet boundary conditions. Then the energy $E(t)$ defined in \eqref{eq:energy} is conserved: $E(t)=E(0)$ for all $t\ge0$.
\end{theorem}

\begin{proof}
The calculation above is rigorous under the stated regularity. One may justify integration by parts using a density argument: approximate initial data by smooth compactly supported functions and pass to the limit. The identity \eqref{eq:energy} follows directly.
\end{proof}

\section{Example: separation of variables in one dimension}
On $\Omega=(0,L)$ consider
\begin{equation}\label{eq:1d_wave}
 u_{tt}-c^2u_{xx}=0, \qquad u(0,t)=u(L,t)=0.
\end{equation}
Seek solutions of the form $u(x,t)=X(x)T(t)$. Separation gives
\begin{equation}\label{eq:sep}
\frac{T''(t)}{c^2T(t)}=\frac{X''(x)}{X(x)}=-\lambda,
\end{equation}
with eigenvalues $\lambda_k=(k\pi/L)^2$, $k\in\mathbb{N}$. The corresponding modes are
\begin{equation}\label{eq:modes}
X_k(x)=\sin\left(\frac{k\pi x}{L}\right), \qquad T_k(t)=A_k\cos(c\sqrt{\lambda_k}t)+B_k\sin(c\sqrt{\lambda_k}t).
\end{equation}
A general solution satisfies the Fourier series
\begin{equation}\label{eq:series}
u(x,t)=\sum_{k=1}^\infty\left(a_k\cos\left(\frac{k\pi c}{L}t\right)+b_k\sin\left(\frac{k\pi c}{L}t\right)\right)\sin\left(\frac{k\pi x}{L}\right),
\end{equation}
with coefficients determined by the initial data. One checks directly that the energy computed mode-by-mode yields a sum of conserved contributions, consistent with Theorem \ref{thm:energy}.

\section{Concluding remarks}
Conservation of energy is a fundamental qualitative property of the wave equation. Inhomogeneous terms or dissipative boundary conditions break exact conservation and require modification of the identity \eqref{eq:energy}. For numerical approximation, discrete analogues of the derivation above are used to design energy-stable schemes. The steps shown here, with explicit labels and numbered displays, are intended to facilitate precise translation while preserving mathematical structure.

