\section{Introduction}
This note presents a compact derivation of the one-dimensional wave equation for a uniform string under tension using the Lagrangian formalism.  We denote the transverse displacement by $u(x,t)$ where $0\le x\le L$.  The string has linear mass density $\rho$ and constant tension $T$.  The aim is to derive the field equation, discuss normal modes, and prove conservation of energy in a simple, self-contained way.

\section{Lagrangian formulation}
The action is constructed from kinetic and potential contributions.  The Lagrangian for the continuous string is
\begin{equation}\label{eq:lagrangian}
L = \int_{0}^{L} \left( \frac{1}{2}\rho \dot{u}^2 - \frac{1}{2}T (\partial_x u)^2 \right) dx ,
\end{equation}
where $\dot{u}=\partial_t u$ and $\partial_x u=\partial u/\partial x$.  We impose fixed-end boundary conditions $u(0,t)=u(L,t)=0$ unless stated otherwise.

Applying the Euler--Lagrange equation for fields,
\begin{equation}
\frac{\partial}{\partial t}\left( \frac{\delta L}{\delta \dot{u}}\right) + \frac{\partial}{\partial x}\left( \frac{\delta L}{\delta (\partial_x u)}\right) - \frac{\delta L}{\delta u} = 0 ,
\end{equation}
one obtains the familiar wave equation
\begin{equation}\label{eq:wave}
\rho \ddot{u} - T \partial_x^2 u = 0.
\end{equation}
It is convenient to define the wave speed
\begin{equation}
c^2 = T/\rho,
\end{equation}
so that \eqref{eq:wave} is equivalently
\begin{equation}
\ddot{u} - c^2 \partial_x^2 u = 0.
\end{equation}

\section{Normal modes and dispersion}
Seeking separable solutions $u(x,t)=X(x)T(t)$ leads to the standard Sturm--Liouville problem.  For fixed ends the spatial eigenfunctions are
\begin{equation}
X_n(x)=\sin\left(\frac{n\pi x}{L}\right),\qquad n=1,2,\dots
\end{equation}
and the corresponding eigenfrequencies satisfy
\begin{equation}\label{eq:omega}
\omega_n = c k_n,\qquad k_n = \frac{n\pi}{L}.
\end{equation}
Therefore the normal-mode solutions may be written as
\begin{equation}\label{eq:modes}
u_n(x,t)=A_n \sin\left(\frac{n\pi x}{L}\right)\cos\left(\omega_n t + \phi_n\right).
\end{equation}
Note that the dispersion relation is linear: $\omega \propto k$, characteristic of nondispersive media.

\section{Energy and a conservation theorem}
The energy density combines kinetic and potential parts.  Define the energy functional
\begin{equation}\label{eq:energy}
E[ u,\dot{u}] = \int_{0}^{L} \left( \frac{1}{2}\rho \dot{u}^2 + \frac{1}{2}T (\partial_x u)^2 \right) dx.
\end{equation}
We state a standard result as a theorem and provide a short proof.

\begin{theorem}\label{thm:energy}
(Conservation of Energy) For solutions of \eqref{eq:wave} with fixed-end boundary conditions, the total energy \eqref{eq:energy} is conserved: $dE/dt=0$.
\end{theorem}

\begin{proof}
Differentiate \eqref{eq:energy} with respect to time and use the field equation \eqref{eq:wave}:
\begin{align}
\frac{dE}{dt} &= \int_{0}^{L} \left( \rho \dot{u}\ddot{u} + T (\partial_x u)(\partial_x \dot{u}) \right) dx \\
&= \int_{0}^{L} \left( \dot{u}(T \partial_x^2 u) + T \partial_x( (\partial_x u)\dot{u} ) - T (\partial_x^2 u)\dot{u} \right) dx = T \left[(\partial_x u)\dot{u}\right]_{0}^{L}=0,
\end{align}
where integration by parts was used and the boundary terms vanish because $u(0,t)=u(L,t)=0$.  Thus $dE/dt=0$.
\end{proof}

\section{Example: first three eigenfrequencies}
For a string of length $L=1\,\mathrm{m}$, tension $T=100\,\mathrm{N}$, and linear density $\rho=0.01\,\mathrm{kg/m}$ one has $c=\sqrt{T/\rho}=100\,\mathrm{m/s}$.  From \eqref{eq:omega} the first three frequencies are
\begin{equation}
\nu_n = \frac{\omega_n}{2\pi} = \frac{c}{2L} n = 50\,n\ \mathrm{Hz},\qquad n=1,2,3.
\end{equation}

\section{Remarks}
The derivation generalizes directly to continua with position-dependent density or tension, in which case $\rho(x)$ and $T(x)$ appear inside the integrals and lead to a non-constant wave speed.  The Lagrangian approach also facilitates the introduction of damping or external forcing via generalized potentials.

