\section{Introduction}
These notes present a worked derivation for the eigenvalues and eigenvectors of a real symmetric $2\times 2$ matrix. The goal is to show step-by-step manipulations that are useful as a reference in applied linear algebra courses. We keep the exposition self-contained and include a short theorem and an illustrative numeric example.

\section{Characteristic Polynomial}
Let
\begin{equation}
A = \begin{pmatrix} a & b \\
 b & c \end{pmatrix}, \qquad a,b,c \in \mathbb{R}.
\end{equation}
The characteristic polynomial is
\begin{equation}\label{eq:char_poly}
p_A(\lambda) = \det(A - \lambda I) = (a-\lambda)(c-\lambda)-b^2.
\end{equation}
Expanding \eqref{eq:char_poly} gives the quadratic
\begin{equation}\label{eq:quad}
\lambda^2 - (a+c)\lambda + (ac-b^2)=0.
\end{equation}
The coefficients are real and the discriminant is
\begin{equation}\label{eq:disc}
\Delta = (a+c)^2 - 4(ac-b^2) = (a-c)^2 + 4b^2 \ge 0,
\end{equation}
which verifies that both eigenvalues are real, as expected for symmetric matrices.

\begin{theorem}\label{thm:2x2}
For the symmetric matrix $A$ above the eigenvalues are given by the closed form
\begin{equation}\label{eq:eigenvalues}
\lambda_{1,2} = \frac{a+c}{2} \pm \frac{1}{2}\sqrt{(a-c)^2+4b^2}.
\end{equation}
Moreover, if $b\neq 0$ the eigenvectors are orthogonal and can be written explicitly.
\end{theorem}

\begin{proof}
Starting from \eqref{eq:quad} we apply the quadratic formula to obtain \eqref{eq:eigenvalues}. To compute eigenvectors for $\lambda_1$ we solve $(A-\lambda_1 I)v=0$. Writing $v=(x,y)^\top$ yields
\begin{equation}
(a-\lambda_1)x + b y = 0, \qquad b x + (c-\lambda_1)y = 0.
\end{equation}
If $b\neq 0$ take $x = 1$ and then
\begin{equation}
y = -\frac{a-\lambda_1}{b}.
\end{equation}
The eigenvector for $\lambda_1$ may be normalized if desired. Orthogonality follows from symmetry: eigenvectors corresponding to distinct eigenvalues of a real symmetric matrix are orthogonal.
\end{proof}

\subsection{Worked numeric example}
Consider
\begin{equation}
A = \begin{pmatrix} 3 & 1 \\
 1 & 2 \end{pmatrix}.
\end{equation}
The trace is $\mathrm{tr}(A)=5$ and the determinant is $\det(A)=5$. The characteristic polynomial is
\begin{equation}
\lambda^2 -5\lambda +5=0.
\end{equation}
Using \eqref{eq:eigenvalues} we get
\begin{equation}
\lambda_{1,2} = \frac{5}{2} \pm \frac{1}{2}\sqrt{(3-2)^2 + 4\cdot 1^2} = \frac{5}{2} \pm \frac{1}{2}\sqrt{5}.
\end{equation}
For $\lambda_1 = \frac{5}{2}+\frac{\sqrt{5}}{2}$ the unnormalized eigenvector is
\begin{equation}
v_1 = \begin{pmatrix} 1 \\
 -\dfrac{3-\lambda_1}{1} \end{pmatrix} = \begin{pmatrix} 1 \\
 \dfrac{\lambda_1-3}{1} \end{pmatrix}.
\end{equation}
A numerical approximation yields $\lambda_1\approx 3.618$ and $v_1\approx (1,0.618)^\top$, which can be normalized to unit length.

\subsection{Remarks}
The closed form in \eqref{eq:eigenvalues} highlights the dependence of the spectral gap on the off-diagonal entry $b$ as well as the difference $a-c$. In applications such as stress analysis or principal component analysis, this explicit solution for $2\times2$ blocks can be used for rapid local computations.

\section{Alternative derivation via rotation}
One may also diagonalize $A$ by an orthogonal rotation $R(\theta)$, where
\begin{equation}
R(\theta)=\begin{pmatrix} \cos\theta & -\sin\theta \\
\sin\theta & \cos\theta \end{pmatrix},
\end{equation}
and choose $\theta$ so that the off-diagonal entry of $R(\theta)^\top A R(\theta)$ vanishes. Solving for $\theta$ leads to the same expressions for $\lambda_{1,2}$ above.

This completes the worked notes for the eigenproblem of a real symmetric $2\times2$ matrix.

%% Derivation sheet: Quantum harmonic oscillator
\section{Introduction}
This note presents a concise derivation of the energy eigenvalues of the one-dimensional quantum harmonic oscillator. The presentation mixes operator techniques and a few remarks about the differential equation form. The Hamiltonian is
\begin{equation}\label{eq:schrodinger}
H = \frac{p^2}{2m} + \frac{1}{2}m\omega^2 x^2,
\end{equation}
with canonical commutation relation $[x,p]=i\hbar$. In position representation $p = -i\hbar\,\frac{d}{dx}$ and the time-independent Schr\"odinger equation reads
\begin{equation}
-\frac{\hbar^2}{2m}\frac{d^2}{dx^2}\psi(x) + \frac{1}{2}m\omega^2 x^2\psi(x) = E\psi(x).
\end{equation}
A useful remark: in three dimensions the kinetic term generalizes to $-(\hbar^2/2m)\nabla^2$, where $\nabla^2$ is the Laplacian.

\section{Ladder operators and algebraic solution}
Define the annihilation and creation operators
\begin{equation}
\begin{aligned}
a &= \sqrt{\frac{m\omega}{2\hbar}}\left(x + \frac{i}{m\omega}p\right), \\
a^{\dagger} &= \sqrt{\frac{m\omega}{2\hbar}}\left(x - \frac{i}{m\omega}p\right).
\end{aligned}
\end{equation}
They satisfy the commutation relation
\begin{equation}
[a,a^{\dagger}] = 1.
\end{equation}
In terms of these operators the Hamiltonian (\ref{eq:schrodinger}) can be written as
\begin{equation}
H = \hbar\omega\left(a^{\dagger}a + \tfrac{1}{2}\right).
\end{equation}

\begin{theorem}
The spectrum of $H$ is discrete and given by
\begin{equation}
E_n = \hbar\omega\left(n + \tfrac{1}{2}\right), \qquad n = 0,1,2,\dots
\end{equation}
\end{theorem}

\begin{proof}
Let $|\psi\rangle$ be an eigenstate with $H|\psi\rangle = E|\psi\rangle$. Define $N = a^{\dagger}a$ so that $H = \hbar\omega(N + 1/2)$. If $|\psi\rangle$ is an eigenstate of $N$ with eigenvalue $n$, then $E = \hbar\omega(n+1/2)$. The operator $a^{\dagger}$ raises $n$ by one and $a$ lowers $n$ by one, since
\begin{equation}
N(a^{\dagger}|n\rangle) = (n+1)(a^{\dagger}|n\rangle), \qquad N(a|n\rangle) = (n-1)(a|n\rangle).
\end{equation}
Positivity of the norm prevents $n$ from decreasing without bound; therefore there exists a ground state $|0\rangle$ defined by $a|0\rangle = 0$. Acting with $N$ on $|0\rangle$ gives $N|0\rangle = 0$, so $n\ge 0$ and is integer-valued. This yields the stated spectrum.
\end{proof}

\section{Differential equation viewpoint and Hermite functions}
Returning to the differential form, introduce dimensionless coordinate $\xi = \sqrt{\frac{m\omega}{\hbar}}\,x$. The Schr\"odinger equation becomes
\begin{equation}
\frac{d^2\psi}{d\xi^2} = (\xi^2 - \lambda)\psi, \quad \lambda = \frac{2E}{\hbar\omega}.
\end{equation}
Requiring square-integrability yields polynomial solutions multiplied by a Gaussian envelope, leading to Hermite functions $H_n(\xi) e^{-\xi^2/2}$ and the quantization condition $\lambda = 2n+1$, reproducing $E_n$ above.

\section{Energy expectation and uncertainties}
For the eigenstate $|n\rangle$ one finds the expectation values
\begin{equation}
\langle x\rangle = 0, \quad \langle p\rangle = 0, \quad \langle x^2\rangle = \frac{\hbar}{2m\omega}(2n+1).
\end{equation}
Consequently the energy splits equally on average between kinetic and potential contributions, and the product of uncertainties satisfies the minimal uncertainty relation for the ground state.

\section{Concluding remarks}
The algebraic ladder method provides a compact derivation of the spectrum and highlights the role of the commutation relations. The differential approach connects the eigenfunctions to orthogonal polynomials and is useful for explicit coordinate-space calculations. Both perspectives are essential for further developments, such as coherent states, perturbations, and path integral treatments.

